var a=class{constructor(e,t,r){this.db=e;this.categoryType=t;this.contentTable=r}async getCategories(e,t,r){return this.db.categories.where("[playlistId+type]").equals([e,this.categoryType]).offset(t).limit(r).toArray()}async getCategory(e,t){return this.db.categories.where("[playlistId+externalId]").equals([e,t]).and(r=>r.type===this.categoryType).first()}async getItemsByCategory(e,t,r,o){return this.contentTable.where("categoryId").equals(t).and(n=>n.playlistId===e).offset(r).limit(o).toArray()}};export{a};
